// El navegador ya valida, pero eso se salta con un curl.
// Esta es la validación real: nada de lo de abajo confía en el cliente.

const salida = [];

for (const item of $input.all()) {
  const b = item.json.body ?? item.json;

  const nombre   = String(b.nombre   ?? '').trim().slice(0, 80);
  const whatsapp = String(b.whatsapp ?? '').trim();
  const correo   = String(b.correo   ?? '').trim().toLowerCase();
  const trampa   = String(b.web      ?? '').trim(); // honeypot: invisible para humanos

  // Formato de correo
  const formatoOk = /^[^\s@]+@[^\s@]+\.[a-z]{2,}$/i.test(correo);

  // Dominios desechables
  const desechables = ['mailinator.com','tempmail.com','10minutemail.com','guerrillamail.com','yopmail.com','trashmail.com','sharklasers.com'];
  const dominio = correo.split('@')[1] || '';
  const esDesechable = desechables.includes(dominio);

  // WhatsApp normalizado a E.164 (7 a 15 dígitos)
  const soloDigitos = whatsapp.replace(/\D/g, '');
  const whatsappOk = soloDigitos.length >= 7 && soloDigitos.length <= 15;

  // Si el honeypot viene lleno, es un bot: se descarta en silencio
  const esBot = trampa.length > 0;

  const valido = Boolean(nombre) && formatoOk && !esDesechable && whatsappOk && !esBot;

  let motivo = '';
  if (esBot)             motivo = 'bot';
  else if (!nombre)      motivo = 'Escribe tu nombre.';
  else if (!formatoOk)   motivo = 'Ese correo no tiene un formato válido.';
  else if (esDesechable) motivo = 'Usa un correo real: ahí es donde te llega la guía.';
  else if (!whatsappOk)  motivo = 'Revisa el número de WhatsApp.';

  salida.push({
    json: {
      nombre,
      whatsapp: soloDigitos ? '+' + soloDigitos : '',
      correo,
      valido,
      motivo,
      fecha: new Date().toISOString(),
      origen: 'pagina-clases-upfunnel'
    }
  });
}

return salida;
